#include <bits/stdc++.h>
using namespace std;
int f[101][101],a[101],n;
int main(){
    memset(f,127,sizeof(f));
    cin>>n;
    for(int i=1;i<=n;i++)f[i][i]=0;
    for(int i=1;i<=n;i++){
        int u,v;
        cin>>a[i]>>u>>v;
        if(u)f[i][u]=f[u][i]=1;
        if(v)f[i][v]=f[v][i]=1;
    }
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(f[i][k]<1<<30 && f[k][j]<1<<30)f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
    /*for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++)cout<<f[i][j]<<' ';
        cout<<endl;
    }*/
    long long ans=pow(2,60);
    //cout<<ans<<endl;
    for(int i=1;i<=n;i++){
    	long long sum=0;
    	for(int j=1;j<=n;j++)sum+=f[i][j]*a[j];
    	//cout<<sum<<endl;
    	ans=min(ans,sum);
	}
	cout<<ans;
    return 0;
}
